1	/**
2	 * HTTP / HTTPS forward proxy listener for sandboxed agents.
3	 *
4	 * Ported from v1 ~/dev/ai/ax/src/host/web-proxy.ts (HTTP forwarding from
5	 * lines 158-349, CONNECT handler from 353-493, handleMITMConnect from
6	 * 497-620, server setup from 622-655).
7	 *
8	 * Cuts from v1:
9	 * - `urlRewrites` block dropped — out of scope for v2.
10	 * - `onApprove` callback dropped — the per-session allowlist is the
11	 *   only egress gate (I2 from the Phase 1a plan).
12	 * - `domainDecisions` cache dropped — only ever cached `onApprove`
13	 *   results, which no longer exist.
14	 * - Canary-on-HTTP-body skipped — only the MITM path scans canary,
15	 *   since HTTP forwarding is rare for LLM/MCP traffic and never
16	 *   carries credential placeholders.
17	 * - `onAudit` is the listener's only audit-emission seam. The plugin
18	 *   wires one that maps each `ProxyAuditEntry` to the public
19	 *   `event.http-egress` payload and fires it on the bus (Task 11).
20	 * - Dynamic `import('./proxy-ca.js')` for `generateDomainCert` inlined
21	 *   to a static import — the v1 lazy load existed only to avoid pulling
22	 *   node-forge into non-MITM proxy modes that no longer exist in v2.
23	 *
24	 * Security:
25	 * - `resolveAndCheck` is called with the request's hostname; the
26	 *   returned IP is then used for the actual upstream connection so a
27	 *   second DNS resolution can't return a different (private) IP. See
28	 *   the SECURITY docstring on `resolveAndCheck`.
29	 * - Allowlist check: a host is allowed iff at least one registered
30	 *   session's `allowlist` contains it. Phase 1a passes `sessions`
31	 *   directly; Task 9 swaps to a per-process map keyed by sessionId.
32	 * - MITM is the default for HTTPS. The minted leaf cert chains to the
33	 *   CA passed via `ProxyListenerOptions.ca`; sandboxed clients trust
34	 *   that CA via the bridge's env-var injection. `bypassMITM` is the
35	 *   per-host opt-out for cert-pinning clients.
36	 */
37	
38	import { createServer, type Server, type IncomingMessage, type ServerResponse } from 'node:http';
39	import * as net from 'node:net';
40	import * as tls from 'node:tls';
41	import { existsSync, unlinkSync } from 'node:fs';
42	import type { AddressInfo } from 'node:net';
43	import { resolveAndCheck, BlockedIPError, type Resolver } from './private-ip.js';
44	import type { SharedCredentialRegistry } from './registry.js';
45	import { generateDomainCert, type CAKeyPair } from './ca.js';
46	
47	// ── Types ────────────────────────────────────────────────────────────
48	
49	/**
50	 * One session's egress policy. Multiple sessions can share a listener;
51	 * the allowlist check ORs across all registered sessions.
52	 */
53	export interface SessionConfig {
54	  /** Hostnames this session is allowed to reach (exact match). */
55	  allowlist: Set<string>;
56	  /** IPs exempt from the private-range block. Test-only escape hatch. */
57	  allowedIPs?: Set<string>;
58	  /**
59	   * Hostnames whose CONNECT requests should bypass MITM and pass through
60	   * as a raw TLS tunnel. Used as the per-session opt-out for cert-pinning
61	   * hosts (e.g. some CLIs that ship a pinned trust store).
62	   *
63	   * Aggregation is "any-bypass-wins": if ANY registered session declares
64	   * bypass for the hostname, the listener takes the safer default and
65	   * skips MITM for that host. Minting a cert for a pinned host would
66	   * break the client; failing closed (raw tunnel, no credential injection)
67	   * is the right call — sessions that wanted MITM still get the bytes
68	   * passed through, just without inspection.
69	   */
70	  bypassMITM?: Set<string>;
71	  /**
72	   * Optional canary token. When MITM is active and any decrypted request
73	   * chunk contains this byte sequence, the proxy aborts with 403 and
74	   * audits `blocked: 'canary_detected'`. Per-session: each session's token
75	   * is checked independently; a chunk matches if ANY session's token is
76	   * present. Used to detect prompt-injection attacks that try to exfiltrate
77	   * a canary string the model was told not to leak.
78	   */
79	  canaryToken?: string;
80	  /**
81	   * Stable session identifier. The plugin sets this on open-session so
82	   * audit emissions can carry it through to `event.http-egress`. Optional
83	   * for back-compat with tests that build SessionConfig directly without
84	   * going through the plugin.
85	   */
86	  sessionId?: string;
87	  /**
88	   * The user this session was opened for. The plugin sets this on
89	   * open-session; the listener attaches it to audit entries so subscribers
90	   * can attribute traffic. Optional for the same back-compat reason as
91	   * `sessionId`.
92	   */
93	  userId?: string;
94	  /**
95	   * Coarse traffic class derived from the session's credential kinds.
96	   * Computed once at open-session time (cheap; kinds don't change for the
97	   * life of a session) and stamped onto every audit entry the listener
98	   * emits for this session.
99	   *
100	   * - `'llm'`: any credential's kind is an LLM kind (`'api-key'` today,
101	   *   future `'anthropic-oauth'` etc).
102	   * - `'mcp'`: Phase 3 will exercise this for `'mcp-*'` kinds.
103	   * - `'other'`: everything else (no credentials, or only non-LLM/non-MCP).
104	   *
105	   * Optional for back-compat — listener-internal SessionConfig built by
106	   * tests that don't go through the plugin won't have it set, and the
107	   * plugin's onAudit callback defaults to `'other'` if missing.
108	   */
109	  classification?: 'llm' | 'mcp' | 'other';
110	}
111	
112	/**
113	 * In-process audit entry the listener hands to its `onAudit` callback.
114	 * Shape is intentionally listener-internal — the plugin maps it to the
115	 * public `event.http-egress` payload (renaming fields, parsing the URL
116	 * into host/path, translating `blocked` → `blockedReason`).
117	 *
118	 * The `blocked` field uses the listener's own vocabulary
119	 * (`'canary_detected'`, `'tls_error: …'`, `'Blocked: …'` from
120	 * BlockedIPError, `'domain_denied: <host>'`, `'invalid_target'`); the
121	 * plugin translates to the bus's `'allowlist' | 'private-ip' | 'canary'
122	 * | 'tls-error'` enumeration.
123	 */
124	export interface ProxyAuditEntry {
125	  action: 'proxy_request';
126	  method: string;
127	  url: string;
128	  status: number;
129	  requestBytes: number;
130	  responseBytes: number;
131	  durationMs: number;
132	  blocked?: string;
133	  /** True iff MITM substitution actually replaced bytes on this connection. */
134	  credentialInjected?: boolean;
135	  /**
136	   * Set when the listener could match the request to a registered session
137	   * (every success case, plus canary/tls-error/private-IP blocks where the
138	   * allowlist check passed). Unset when no session matched (allowlist miss
139	   * — the request never had an owner to begin with).
140	   */
141	  sessionId?: string;
142	  /** Same lifecycle as `sessionId`; copied from the matching session. */
143	  userId?: string;
144	  /** Same lifecycle as `sessionId`; copied from the matching session. */
145	  classification?: 'llm' | 'mcp' | 'other';
146	}
147	
148	export interface ProxyListenerOptions {
149	  /** Where to listen. TCP on a host:port, or a Unix socket path. */
150	  listen: { kind: 'tcp'; host?: string; port?: number } | { kind: 'unix'; path: string };
151	  /** Shared credential registry — touched on the MITM path (Task 8). */
152	  registry: SharedCredentialRegistry;
153	  /** Per-session configs. Phase 1a: passed in; Task 9: per-process map. */
154	  sessions: Map<string, SessionConfig>;
155	  /**
156	   * Root CA used to mint per-domain leaf certs on the MITM path. Required —
157	   * MITM is the default for HTTPS, and we can't terminate TLS without one.
158	   * Tests pass a CA minted in tmpdir; production uses `getOrCreateCA(dir)`.
159	   */
160	  ca: CAKeyPair;
161	  /**
162	   * Optional audit sink — defaults to no-op. The plugin provides one that
163	   * maps `ProxyAuditEntry` → `event.http-egress` and fires on the bus.
164	   * Tests may pass a sync function that just collects entries.
165	   */
166	  onAudit?: (entry: ProxyAuditEntry) => void;
167	  /** Optional DNS resolver override — for tests. Default: dns.promises.lookup. */
168	  resolver?: Resolver;
169	}
170	
171	export interface ProxyListener {
172	  /** TCP port (0 when listening on a Unix socket). */
173	  port: number;
174	  /** Full address — TCP port number or Unix socket path string. */
175	  address: string | number;
176	  stop(): void;
177	}
178	
179	// ── Allowlist check ──────────────────────────────────────────────────
180	
181	/**
182	 * A hostname is allowed iff some registered session's allowlist contains it.
183	 * Returns the allowedIPs override of the FIRST matching session, or undefined.
184	 *
185	 * Phase 1a uses exact-match. Wildcards are deliberately out of scope —
186	 * the bridge passes literal hostnames extracted from the URL.
187	 */
188	function findAllowingSession(
189	  hostname: string,
190	  sessions: Map<string, SessionConfig>,
191	): SessionConfig | undefined {
192	  for (const session of sessions.values()) {
193	    if (session.allowlist.has(hostname)) return session;
194	  }
195	  return undefined;
196	}
197	
198	/**
199	 * Returns true iff ANY registered session has the hostname in `bypassMITM`.
200	 *
201	 * "Any wins" is the safer default — minting a leaf cert for a cert-pinned
202	 * host would break the pinned client. If even one session asked us not to
203	 * intercept this host, we honor it for all sessions sharing the listener.
204	 * Sessions that wanted MITM still get bytes through, just unwrapped.
205	 */
206	function findAnyBypassingSession(
207	  hostname: string,
208	  sessions: Map<string, SessionConfig>,
209	): boolean {
210	  for (const session of sessions.values()) {
211	    if (session.bypassMITM?.has(hostname)) return true;
212	  }
213	  return false;
214	}
215	
216	/** Collect all canary tokens declared across sessions, deduped + non-empty. */
217	function collectCanaryTokens(sessions: Map<string, SessionConfig>): string[] {
218	  const tokens = new Set<string>();
219	  for (const session of sessions.values()) {
220	    if (session.canaryToken) tokens.add(session.canaryToken);
221	  }
222	  return [...tokens];
223	}
224	
225	// ── Listener ─────────────────────────────────────────────────────────
226	
227	export async function startProxyListener(opts: ProxyListenerOptions): Promise<ProxyListener> {
228	  const { listen, sessions, onAudit, resolver, registry, ca } = opts;
229	  const activeSockets = new Set<net.Socket>();
230	
231	  function audit(entry: ProxyAuditEntry): void {
232	    onAudit?.(entry);
233	  }
234	
235	  /**
236	   * Copy the session-stamping fields (`sessionId`, `userId`, `classification`)
237	   * off `session` onto an audit entry. No-op if `session` is undefined
238	   * (allowlist-miss + invalid-target paths can't attribute to a session).
239	   *
240	   * `exactOptionalPropertyTypes` means we only set keys when defined;
241	   * setting `key: undefined` is a type error.
242	   */
243	  function stampSession(
244	    entry: ProxyAuditEntry,
245	    session: SessionConfig | undefined,
246	  ): ProxyAuditEntry {
247	    if (!session) return entry;
248	    if (session.sessionId !== undefined) entry.sessionId = session.sessionId;
249	    if (session.userId !== undefined) entry.userId = session.userId;
250	    if (session.classification !== undefined) entry.classification = session.classification;
251	    return entry;
252	  }
253	
254	  // ── HTTP request forwarding ──
255	
256	  async function handleHTTPRequest(req: IncomingMessage, res: ServerResponse): Promise<void> {
257	    const startTime = Date.now();
258	    const method = req.method ?? 'GET';
259	    const url = req.url ?? '/';
260	    let requestBytes = 0;
261	    let responseBytes = 0;
262	
263	    try {
264	      // The bridge forwards the absolute URL in `req.url` (HTTP-proxy convention).
265	      // Fall back to constructing one from the Host header so direct curl-style
266	      // fetches against the listener also work.
267	      const targetUrl = url.startsWith('http://') || url.startsWith('https://')
268	        ? new URL(url)
269	        : new URL(url, `http://${req.headers.host ?? 'unknown'}`);
270	
271	      // Strip IPv6 brackets if present
272	      const hostname =
273	        targetUrl.hostname.startsWith('[') && targetUrl.hostname.endsWith(']')
274	          ? targetUrl.hostname.slice(1, -1)
275	          : targetUrl.hostname;
276	
277	      // Allowlist gate (I2): hostname must be in some session's allowlist.
278	      const allowingSession = findAllowingSession(hostname, sessions);
279	      if (!allowingSession) {
280	        // No matching session → no sessionId/userId/classification to stamp.
281	        // The audit just carries the block reason; the plugin's onAudit will
282	        // emit the bus event with `blockedReason: 'allowlist'` and the
283	        // session-attribution fields left empty.
284	        audit({
285	          action: 'proxy_request',
286	          method,
287	          url,
288	          status: 403,
289	          requestBytes: 0,
290	          responseBytes: 0,
291	          durationMs: Date.now() - startTime,
292	          blocked: `domain_denied: ${hostname}`,
293	        });
294	        res.writeHead(403, { 'Content-Type': 'text/plain' });
295	        res.end(
296	          `Domain ${hostname} is not in any session allowlist. Install a skill that declares this domain, or ask an admin to approve it.`,
297	        );
298	        return;
299	      }
300	
301	      // SSRF block (I3): resolve and verify against private CIDRs.
302	      // Use the returned IP for the upstream connection — DO NOT re-resolve
303	      // (DNS rebinding defense). See SECURITY note on resolveAndCheck.
304	      const resolvedIP = await resolveAndCheck(hostname, allowingSession.allowedIPs, resolver);
305	
306	      // Read request body
307	      const chunks: Buffer[] = [];
308	      for await (const chunk of req) {
309	        chunks.push(chunk as Buffer);
310	      }
311	      const body = Buffer.concat(chunks);
312	      requestBytes = body.length;
313	
314	      // Forward headers (strip hop-by-hop and encoding headers — fetch handles these).
315	      const headers: Record<string, string> = {};
316	      for (const [key, value] of Object.entries(req.headers)) {
317	        if (
318	          !value ||
319	          key === 'host' ||
320	          key === 'connection' ||
321	          key === 'proxy-connection' ||
322	          key === 'transfer-encoding' ||
323	          key === 'content-length'
324	        )
325	          continue;
326	        headers[key] = Array.isArray(value) ? value.join(', ') : value;
327	      }
328	      // Preserve the original Host so the upstream sees vhost-correct routing.
329	      headers['host'] = targetUrl.host;
330	
331	      // Build the upstream URL using the resolved IP (DNS rebinding defense).
332	      // For IPv6, re-bracket the literal so URL parsing accepts it.
333	      const ipForUrl = net.isIPv6(resolvedIP) ? `[${resolvedIP}]` : resolvedIP;
334	      const upstreamUrl = new URL(targetUrl.toString());
335	      upstreamUrl.hostname = ipForUrl;
336	
337	      // Forward via fetch and stream response back.
338	      const response = await fetch(upstreamUrl.toString(), {
339	        method,
340	        headers,
341	        ...(body.length > 0 ? { body } : {}),
342	        redirect: 'manual',
343	      });
344	
345	      const outHeaders: Record<string, string> = {};
346	      response.headers.forEach((v, k) => {
347	        if (k !== 'transfer-encoding' && k !== 'content-encoding' && k !== 'content-length') {
348	          outHeaders[k] = v;
349	        }
350	      });
351	      res.writeHead(response.status, outHeaders);
352	
353	      if (response.body) {
354	        const reader = response.body.getReader();
355	        try {
356	          while (true) {
357	            const { done, value } = await reader.read();
358	            if (done) break;
359	            responseBytes += value.length;
360	            res.write(value);
361	          }
362	        } finally {
363	          reader.releaseLock();
364	        }
365	      }
366	      res.end();
367	
368	      audit(stampSession({
369	        action: 'proxy_request',
370	        method,
371	        url,
372	        status: response.status,
373	        requestBytes,
374	        responseBytes,
375	        durationMs: Date.now() - startTime,
376	      }, allowingSession));
377	    } catch (err) {
378	      // BlockedIPError → 403 (policy block); anything else → 502 (network/DNS).
379	      // Reviewer M3 from Task 5: use typed instanceof, not string match.
380	      const isBlocked = err instanceof BlockedIPError;
381	      const status = isBlocked ? 403 : 502;
382	      const message = isBlocked
383	        ? (err as BlockedIPError).message
384	        : `Proxy error: ${(err as Error).message}`;
385	
386	      if (!res.headersSent) {
387	        res.writeHead(status, { 'Content-Type': 'text/plain' });
388	      }
389	      res.end(message);
390	
391	      // Re-resolve the matching session for stamping. The catch can fire
392	      // either before or after `allowingSession` was set in the try block,
393	      // and `allowingSession` isn't in scope here. Re-running the lookup is
394	      // cheap (Map.values iteration over a tiny set) and keeps the flow
395	      // straightforward.
396	      const hostnameForCatch = (() => {
397	        try {
398	          return new URL(
399	            url.startsWith('http://') || url.startsWith('https://')
400	              ? url
401	              : `http://${req.headers.host ?? 'unknown'}${url}`,
402	          ).hostname;
403	        } catch {
404	          return undefined;
405	        }
406	      })();
407	      const sessionForCatch = hostnameForCatch
408	        ? findAllowingSession(hostnameForCatch, sessions)
409	        : undefined;
410	      const blockedEntry: ProxyAuditEntry = {
411	        action: 'proxy_request',
412	        method,
413	        url,
414	        status,
415	        requestBytes,
416	        responseBytes: 0,
417	        durationMs: Date.now() - startTime,
418	      };
419	      if (isBlocked) blockedEntry.blocked = message;
420	      audit(stampSession(blockedEntry, sessionForCatch));
421	    }
422	  }
423	
424	  // ── HTTPS CONNECT — MITM path (TLS terminate, substitute, canary scan) ──
425	  //
426	  // Ported from v1 ~/dev/ai/ax/src/host/web-proxy.ts:497-620 with adaptations:
427	  //  - `options.mitm.credentials` → the per-session view of the shared
428	  //    `SharedCredentialRegistry` already passed to the listener. One tunnel
429	  //    sees ALL active sessions' placeholders; cross-session collision is
430	  //    statistically infeasible (16 random bytes per placeholder).
431	  //  - `generateDomainCert` static-imported (no longer dynamic).
432	  //  - `canaryToken` aggregated across sessions (per-session field, not
433	  //    a single global option). A chunk matches if any session's token is in it.
434	  //  - `sessionId`/`userId`/`classification` are stamped via `stampSession`
435	  //    from the SessionConfig that allowed the request. The plugin sets
436	  //    those fields at `proxy:open-session` time (Task 11).
437	
438	  async function handleMITMConnect(
439	    clientSocket: net.Socket,
440	    hostname: string,
441	    port: number,
442	    resolvedIP: string,
443	    head: Buffer,
444	    startTime: number,
445	    target: string,
446	    allowingSession: SessionConfig,
447	  ): Promise<void> {
448	    const domainCert = generateDomainCert(hostname, ca);
449	
450	    // Tell the client the tunnel is established before kicking off TLS.
451	    clientSocket.write('HTTP/1.1 200 Connection Established\r\n\r\n');
452	
453	    // Suppress raw-socket errors so an abrupt client disconnect during the
454	    // TLS handshake doesn't crash with an unhandled 'error' — the TLS wrapper
455	    // cleanup paths handle teardown.
456	    clientSocket.on('error', () => { /* handled by TLS wrapper cleanup */ });
457	
458	    // Terminate the client's TLS with our minted leaf cert.
459	    const clientTls = new tls.TLSSocket(clientSocket, {
460	      isServer: true,
461	      key: domainCert.key,
462	      cert: domainCert.cert,
463	    });
464	
465	    // Connect to the upstream by RESOLVED IP (DNS rebinding defense), with
466	    // SNI = original hostname. Trust store = real roots PLUS our CA so test
467	    // upstreams signed by the same CA are accepted without disabling cert
468	    // verification. RFC 6066 forbids SNI for IP literals, so omit servername
469	    // when the hostname is an IP address (avoids a Node deprecation warning).
470	    const targetTls = tls.connect({
471	      host: resolvedIP,
472	      port,
473	      ca: [...tls.rootCertificates, ca.cert],
474	      ...(net.isIP(hostname) ? {} : { servername: hostname }),
475	    });
476	
477	    activeSockets.add(clientTls);
478	    activeSockets.add(targetTls);
479	
480	    // Track upstream TLS handshake failure separately so the cleanup audit
481	    // doesn't double-log a 200 over the actual 502.
482	    let tlsFailed = false;
483	    targetTls.on('error', (err) => {
484	      if (!tlsFailed) {
485	        tlsFailed = true;
486	        audit(stampSession({
487	          action: 'proxy_request',
488	          method: 'CONNECT',
489	          url: target,
490	          status: 502,
491	          requestBytes: head.length,
492	          responseBytes: 0,
493	          durationMs: Date.now() - startTime,
494	          blocked: `tls_error: ${err.message}`,
495	        }, allowingSession));
496	      }
497	    });
498	
499	    let requestBytes = head.length;
500	    let responseBytes = 0;
501	    let credentialInjected = false;
502	
503	    // canaryTokens are computed once per connection — sessions don't change
504	    // mid-tunnel under our model.
505	    const canaryTokens = collectCanaryTokens(sessions);
506	
507	    // client → (canary scan, then credential substitute) → upstream
508	    clientTls.on('data', (chunk: Buffer) => {
509	      requestBytes += chunk.length;
510	
511	      // Canary scan first — substitution doesn't affect canary detection,
512	      // but checking before substitution means we see the bytes the model
513	      // actually wrote (the placeholder→real swap is on the credential
514	      // bytes, not on canaries).
515	      for (const token of canaryTokens) {
516	        if (chunk.includes(token)) {
517	          audit(stampSession({
518	            action: 'proxy_request',
519	            method: 'CONNECT',
520	            url: target,
521	            status: 403,
522	            requestBytes,
523	            responseBytes: 0,
524	            durationMs: Date.now() - startTime,
525	            blocked: 'canary_detected',
526	          }, allowingSession));
527	          // Send a 403 over the TLS channel before tearing down.
528	          clientTls.write('HTTP/1.1 403 Forbidden\r\nContent-Length: 0\r\nConnection: close\r\n\r\n');
529	          clientTls.end();
530	          targetTls.destroy();
531	          return;
532	        }
533	      }
534	
535	      const replaced = registry.replaceAllBuffer(chunk);
536	      if (replaced !== chunk) credentialInjected = true;
537	      targetTls.write(replaced);
538	    });
539	
540	    // upstream → client (no substitution on response — placeholders should
541	    // never originate upstream).
542	    targetTls.on('data', (chunk: Buffer) => {
543	      responseBytes += chunk.length;
544	      clientTls.write(chunk);
545	    });
546	
547	    // Flush any inner-TLS bytes the client sent before our upstream socket
548	    // existed. MUST happen BEFORE we'd otherwise let a clientTls 'data'
549	    // listener race ahead — same lesson as the Task 7 head-buffer fix.
550	    // ClientHello bytes won't typically contain placeholders, but run them
551	    // through replaceAllBuffer anyway in case the head straddles a request
552	    // boundary on a long-lived tunnel.
553	    if (head.length > 0) {
554	      const replaced = registry.replaceAllBuffer(head);
555	      if (replaced !== head) credentialInjected = true;
556	      targetTls.write(replaced);
557	    }
558	
559	    // Cleanup once — first close/error wins, downstream events become no-ops.
560	    let cleaned = false;
561	    const cleanup = () => {
562	      if (cleaned) return;
563	      cleaned = true;
564	      activeSockets.delete(clientTls);
565	      activeSockets.delete(targetTls);
566	      clientTls.destroy();
567	      targetTls.destroy();
568	
569	      // Skip the 200 audit if a TLS handshake error already logged 502.
570	      if (!tlsFailed) {
571	        audit(stampSession({
572	          action: 'proxy_request',
573	          method: 'CONNECT',
574	          url: target,
575	          status: 200,
576	          requestBytes,
577	          responseBytes,
578	          durationMs: Date.now() - startTime,
579	          // Omit `credentialInjected` when false to satisfy
580	          // exactOptionalPropertyTypes — only present when substitution fired.
581	          ...(credentialInjected ? { credentialInjected: true as const } : {}),
582	        }, allowingSession));
583	      }
584	    };
585	
586	    clientTls.on('close', cleanup);
587	    clientTls.on('error', cleanup);
588	    targetTls.on('close', cleanup);
589	    targetTls.on('error', cleanup);
590	  }
591	
592	  // ── HTTPS CONNECT — MITM (default) or raw TCP tunnel (bypassMITM hosts) ──
593	  //
594	  // Ported from v1 ~/dev/ai/ax/src/host/web-proxy.ts:353-493 (allowlist + DNS
595	  // gates) and 497-620 (handleMITMConnect). Cuts vs. v1:
596	  //  - urlRewrites block dropped (out of scope for v2).
597	  //  - onApprove dropped — per-session allowlist is the only egress gate.
598	  //  - sessionId/userId/classification are stamped on audit entries via
599	  //    `stampSession` from the matching SessionConfig (Task 11).
600	  //  - bypassDomains field renamed to per-session bypassMITM, aggregated
601	  //    "any-bypass-wins" so cert-pinning hosts never get a minted cert.
602	  //
603	  // MITM is the default. If the hostname is NOT in any session's bypassMITM,
604	  // traffic is intercepted with a dynamically-minted domain cert and decrypted
605	  // in-process for credential injection + canary scanning. Hosts in
606	  // bypassMITM fall through to the raw-tunnel path below (no inspection).
607	
608	  async function handleCONNECT(
609	    req: IncomingMessage,
610	    clientSocket: net.Socket,
611	    head: Buffer,
612	  ): Promise<void> {
613	    const startTime = Date.now();
614	    const target = req.url ?? '';
615	    let requestBytes = head.length;
616	    let responseBytes = 0;
617	
618	    // Parse host:port from CONNECT target ("host:port")
619	    const [hostname, portStr] = target.split(':');
620	    const port = parseInt(portStr ?? '443', 10);
621	
622	    if (!hostname || Number.isNaN(port)) {
623	      clientSocket.write('HTTP/1.1 400 Bad Request\r\n\r\n');
624	      clientSocket.end();
625	      audit({
626	        action: 'proxy_request',
627	        method: 'CONNECT',
628	        url: target,
629	        status: 400,
630	        requestBytes: 0,
631	        responseBytes: 0,
632	        durationMs: Date.now() - startTime,
633	        blocked: 'invalid_target',
634	      });
635	      return;
636	    }
637	
638	    try {
639	      // Allowlist gate (I2): hostname must be in some session's allowlist.
640	      const allowingSession = findAllowingSession(hostname, sessions);
641	      if (!allowingSession) {
642	        clientSocket.write('HTTP/1.1 403 Forbidden\r\n\r\n');
643	        clientSocket.end();
644	        // No matching session — same shape as the HTTP allowlist-miss case.
645	        audit({
646	          action: 'proxy_request',
647	          method: 'CONNECT',
648	          url: target,
649	          status: 403,
650	          requestBytes: 0,
651	          responseBytes: 0,
652	          durationMs: Date.now() - startTime,
653	          blocked: `domain_denied: ${hostname}`,
654	        });
655	        return;
656	      }
657	
658	      // SSRF block (I3): resolve and verify against private CIDRs.
659	      // Use the returned IP for the upstream connection — DO NOT re-resolve
660	      // (DNS rebinding defense). See SECURITY note on resolveAndCheck.
661	      const resolvedIP = await resolveAndCheck(hostname, allowingSession.allowedIPs, resolver);
662	
663	      // MITM unless ANY session has the host in bypassMITM (any-bypass-wins).
664	      const shouldMitm = !findAnyBypassingSession(hostname, sessions);
665	      if (shouldMitm) {
666	        await handleMITMConnect(
667	          clientSocket,
668	          hostname,
669	          port,
670	          resolvedIP,
671	          head,
672	          startTime,
673	          target,
674	          allowingSession,
675	        );
676	        return;
677	      }
678	
679	      // Open the raw TCP tunnel against the resolved IP.
680	      const targetSocket = net.connect(port, resolvedIP, () => {
681	        clientSocket.write('HTTP/1.1 200 Connection Established\r\n\r\n');
682	        activeSockets.add(targetSocket);
683	
684	        // Byte counters wired BEFORE pipe() — pipe() subscribes its own
685	        // 'data' listener; setting ours first removes the ordering brittleness.
686	        targetSocket.on('data', (chunk: Buffer) => {
687	          responseBytes += chunk.length;
688	        });
689	        clientSocket.on('data', (chunk: Buffer) => {
690	          requestBytes += chunk.length;
691	        });
692	
693	        // Flush any bytes the client sent before the upstream opened — MUST
694	        // happen before pipe() wires clientSocket → targetSocket, otherwise
695	        // a racing client chunk could land on the upstream ahead of `head`
696	        // and corrupt the TLS ClientHello.
697	        if (head.length > 0) {
698	          targetSocket.write(head);
699	        }
700	
701	        // Pipe bidirectionally — neither side's bytes are inspected here.
702	        targetSocket.pipe(clientSocket);
703	        clientSocket.pipe(targetSocket);
704	      });
705	
706	      // Cleanup once — first close/error wins, downstream events become no-ops.
707	      let cleaned = false;
708	      const cleanup = () => {
709	        if (cleaned) return;
710	        cleaned = true;
711	        activeSockets.delete(targetSocket);
712	        targetSocket.destroy();
713	        clientSocket.destroy();
714	
715	        audit(stampSession({
716	          action: 'proxy_request',
717	          method: 'CONNECT',
718	          url: target,
719	          status: 200,
720	          requestBytes,
721	          responseBytes,
722	          durationMs: Date.now() - startTime,
723	        }, allowingSession));
724	      };
725	
726	      targetSocket.on('close', cleanup);
727	      targetSocket.on('error', cleanup);
728	      clientSocket.on('close', cleanup);
729	      clientSocket.on('error', cleanup);
730	    } catch (err) {
731	      // BlockedIPError → 403 (policy block); anything else → 502 (network/DNS).
732	      // Reviewer M3 from Task 5: typed instanceof, not string match.
733	      const isBlocked = err instanceof BlockedIPError;
734	      const status = isBlocked ? 403 : 502;
735	
736	      clientSocket.write(
737	        `HTTP/1.1 ${status} ${isBlocked ? 'Forbidden' : 'Bad Gateway'}\r\n\r\n`,
738	      );
739	      clientSocket.end();
740	
741	      // The catch fires either before or after `allowingSession` was set
742	      // in the try block; re-resolve via hostname to attribute when possible.
743	      // Allowlist hits with a private-IP block (BlockedIPError) DO have a
744	      // matching session — the resolveAndCheck call only runs after the
745	      // allowlist gate passed.
746	      const sessionForCatch = findAllowingSession(hostname, sessions);
747	      const blockedEntry: ProxyAuditEntry = {
748	        action: 'proxy_request',
749	        method: 'CONNECT',
750	        url: target,
751	        status,
752	        requestBytes: 0,
753	        responseBytes: 0,
754	        durationMs: Date.now() - startTime,
755	      };
756	      if (isBlocked) blockedEntry.blocked = (err as BlockedIPError).message;
757	      audit(stampSession(blockedEntry, sessionForCatch));
758	    }
759	  }
760	
761	  // ── Server setup ──
762	
763	  const server: Server = createServer(handleHTTPRequest);
764	  server.on('connect', handleCONNECT);
765	
766	  server.on('connection', (socket) => {
767	    activeSockets.add(socket);
768	    socket.on('close', () => activeSockets.delete(socket));
769	  });
770	
771	  // Clean up stale Unix socket
772	  if (listen.kind === 'unix' && existsSync(listen.path)) {
773	    unlinkSync(listen.path);
774	  }
775	
776	  const stopFn = () => {
777	    for (const s of activeSockets) s.destroy();
778	    activeSockets.clear();
779	    server.close();
780	    if (listen.kind === 'unix') {
781	      try {
782	        unlinkSync(listen.path);
783	      } catch {
784	        /* ignore */
785	      }
786	    }
787	  };
788	
789	  if (listen.kind === 'unix') {
790	    await new Promise<void>((resolve) => {
791	      server.listen(listen.path, () => resolve());
792	    });
793	    return { port: 0, address: listen.path, stop: stopFn };
794	  }
795	
796	  // TCP mode
797	  const host = listen.host ?? '127.0.0.1';
798	  const port = listen.port ?? 0;
799	  const assignedPort = await new Promise<number>((resolve) => {
800	    server.listen(port, host, () => {
801	      resolve((server.address() as AddressInfo).port);
802	    });
803	  });
804	  return { port: assignedPort, address: assignedPort, stop: stopFn };
805	}
