19	
20	  /**
21	   * Register a credential and return its placeholder token.
22	   * If the same name is registered twice, the previous mapping is replaced.
23	   */
24	  register(envName: string, realValue: string): string {
25	    // Remove old mapping if re-registering
26	    const oldPh = this.nameToPlaceholder.get(envName);
27	    if (oldPh) this.placeholderToReal.delete(oldPh);
28	
29	    const placeholder = `ax-cred:${randomBytes(16).toString('hex')}`;
30	    this.placeholderToReal.set(placeholder, realValue);
31	    this.nameToPlaceholder.set(envName, placeholder);
32	    return placeholder;
33	  }
34	
35	  /**
36	   * Update the real value for an already-registered envName WITHOUT minting
37	   * a new placeholder. The sandbox's env still carries the original
38	   * `ax-cred:<hex>`; the proxy now substitutes the new value at request
39	   * time. This is the contract that makes proxy:rotate-session safe for a
40	   * running sandbox — a fresh placeholder would break running SDKs that
41	   * have already read the env (Phase 3 I11).
42	   *
43	   * Returns the existing placeholder, or `undefined` if envName was never
44	   * registered.
45	   */
46	  updateValue(envName: string, realValue: string): string | undefined {
47	    const placeholder = this.nameToPlaceholder.get(envName);
48	    if (placeholder === undefined) return undefined;
49	    this.placeholderToReal.set(placeholder, realValue);
50	    return placeholder;
51	  }
52	
53	  /** Check if a string contains any registered placeholders. */
54	  hasPlaceholders(input: string): boolean {
55	    for (const ph of this.placeholderToReal.keys()) {
56	      if (input.includes(ph)) return true;
57	    }
58	    return false;
59	  }
60	
61	  /** Replace all placeholders in a string with real values. */
62	  replaceAll(input: string): string {
63	    let result = input;
64	    for (const [ph, real] of this.placeholderToReal) {
65	      // Use split+join for global replacement (no regex special chars concern)
66	      result = result.split(ph).join(real);
67	    }
68	    return result;
69	  }
70	
71	  /** Replace all placeholders in a Buffer. Returns a new Buffer.
72	   *  Assumes UTF-8 content (HTTP headers, JSON bodies). Binary data
73	   *  (file uploads, protobuf) passes through unchanged because placeholders
74	   *  are ASCII strings that won't appear in non-text content. */
75	  replaceAllBuffer(input: Buffer): Buffer {
76	    const str = input.toString('utf-8');
77	    if (!this.hasPlaceholders(str)) return input;
78	    return Buffer.from(this.replaceAll(str));
79	  }
80	
81	  /** Return env var name → placeholder map for sandbox injection. */
82	  toEnvMap(): Record<string, string> {
83	    const result: Record<string, string> = {};
84	    for (const [name, ph] of this.nameToPlaceholder) {
85	      result[name] = ph;
86	    }
87	    return result;
88	  }
89	}
