91	/**
92	 * Aggregates per-session CredentialPlaceholderMaps so a shared proxy
93	 * (e.g. k8s) can replace placeholders from any active session.
94	 *
95	 * Placeholders are globally unique (ax-cred:<random>), so there's no
96	 * cross-session collision risk.
97	 */
98	export class SharedCredentialRegistry {
99	  private readonly sessions = new Map<string, CredentialPlaceholderMap>();
100	
101	  /** Register a session's credential map. Called at sandbox launch. */
102	  register(sessionId: string, map: CredentialPlaceholderMap): void {
103	    this.sessions.set(sessionId, map);
104	  }
105	
106	  /** Deregister a session's credential map. Called at session cleanup. */
107	  deregister(sessionId: string): void {
108	    this.sessions.delete(sessionId);
109	  }
110	
111	  /**
112	   * Look up a session's existing credential map. proxy:rotate-session uses
113	   * this to update values on the same map (preserving placeholders) rather
114	   * than minting a fresh map (which would invalidate the sandbox's env).
115	   */
116	  get(sessionId: string): CredentialPlaceholderMap | undefined {
117	    return this.sessions.get(sessionId);
118	  }
119	
120	  /** Check if any registered session has placeholders in the input. */
121	  hasPlaceholders(input: string): boolean {
122	    for (const map of this.sessions.values()) {
123	      if (map.hasPlaceholders(input)) return true;
124	    }
125	    return false;
126	  }
127	
128	  /** Replace placeholders from all active sessions. */
129	  replaceAll(input: string): string {
130	    let result = input;
131	    for (const map of this.sessions.values()) {
132	      result = map.replaceAll(result);
133	    }
134	    return result;
135	  }
136	
137	  /** Replace placeholders in a Buffer across all active sessions.
138	   *  Assumes UTF-8 content. See CredentialPlaceholderMap.replaceAllBuffer. */
139	  replaceAllBuffer(input: Buffer): Buffer {
140	    const str = input.toString('utf-8');
141	    if (!this.hasPlaceholders(str)) return input;
142	    return Buffer.from(this.replaceAll(str));
143	  }
144	}
