1	/**
2	 * @ax/credential-proxy — host-side egress + credential injection plugin.
3	 *
4	 * Boot sequence:
5	 *  1. Resolve config (defaults `caDir = ~/.ax/proxy-ca`).
6	 *  2. Get-or-create the MITM CA.
7	 *  3. Start the listener with an empty session-config Map. The plugin
8	 *     keeps a shared reference to that Map and mutates it directly as
9	 *     `proxy:open-session` / `proxy:close-session` fire — no setter
10	 *     methods on the listener (it already iterates `.values()`).
11	 *     Pass `onAudit` so each `ProxyAuditEntry` becomes an
12	 *     `event.http-egress` bus fire (Task 11).
13	 *  4. Register the three service hooks (open / rotate / close).
14	 *
15	 * `event.http-egress` payload shape lives in `HttpEgressEvent` below
16	 * (mirrors the architecture spec). Subscribers can throw — HookBus.fire
17	 * isolates throws + logs them; the proxy keeps running.
18	 *
19	 * Shutdown: stop the listener (this also closes any active sockets and
20	 * unlinks the Unix socket file when applicable).
21	 *
22	 * The `credentials:get` shape used here is the Phase 3 reshape:
23	 * `({ ref, userId }) → string`. The env-name → placeholder mapping
24	 * doesn't depend on the credentials API shape — this plugin only
25	 * needs to receive the resolved string per ref.
26	 */
27	
28	import { homedir } from 'node:os';
29	import { join } from 'node:path';
30	import { PluginError, makeAgentContext, type AgentContext, type Plugin } from '@ax/core';
31	import {
32	  startProxyListener,
33	  type ProxyListener,
34	  type ProxyAuditEntry,
35	  type SessionConfig,
36	} from './listener.js';
37	import { CredentialPlaceholderMap, SharedCredentialRegistry } from './registry.js';
38	import { getOrCreateCA } from './ca.js';
39	
40	const PLUGIN_NAME = '@ax/credential-proxy';
41	
42	// ── event.http-egress payload shape (architecture spec) ───────────────
43	
44	/**
45	 * Public event payload fired on every proxy request — success, block, or
46	 * upstream error. Subscribers (audit-log writers, billing, anomaly
47	 * detection, security observers) can key off any field, but the listener-
48	 * internal `ProxyAuditEntry` shape is NOT part of the contract.
49	 *
50	 * Field semantics:
51	 * - `host`/`path` are split from the request URL; for CONNECT (`host:port`)
52	 *   `path` is `'/'`.
53	 * - `credentialInjected` is `true` only when MITM substitution actually
54	 *   replaced bytes (HTTP forwarding never substitutes; bypassMITM never
55	 *   substitutes; MITM only sets it when a placeholder matched).
56	 * - `blockedReason` is omitted on success; on a block, it's one of the
57	 *   four enumerated reasons (vocabulary normalized from the listener's
58	 *   internal `blocked` string).
59	 * - `sessionId`/`userId` are empty strings when no session matched
60	 *   (allowlist miss — the request never had an owner).
61	 */
62	export interface HttpEgressEvent {
63	  sessionId: string;
64	  userId: string;
65	  method: string;
66	  host: string;
67	  path: string;
68	  status: number;
69	  requestBytes: number;
70	  responseBytes: number;
71	  durationMs: number;
72	  credentialInjected: boolean;
73	  classification: 'llm' | 'mcp' | 'other';
74	  blockedReason?: 'allowlist' | 'private-ip' | 'canary' | 'tls-error';
75	  timestamp: number;
76	}
77	
78	/**
79	 * Map a per-session credentials record to a coarse classification.
80	 *
81	 * - `'llm'`: any credential whose kind is an LLM kind. Phase 1a recognizes
82	 *   `'api-key'`; future kinds matching the `anthropic-*` pattern (e.g.
83	 *   `'anthropic-oauth'`) also count as LLM.
84	 * - `'mcp'`: any credential whose kind starts with `'mcp-'` (Phase 3 wires
85	 *   real MCP credential kinds; Phase 1a never returns this).
86	 * - `'other'`: empty credentials, or only kinds outside the above sets.
87	 *
88	 * Precedence: `'llm'` wins over `'mcp'` if both appear (rare in practice;
89	 * a session usually has one kind of traffic).
90	 */
91	function classifyCredentials(
92	  credentials: Record<string, { ref: string; kind: string }>,
93	): 'llm' | 'mcp' | 'other' {
94	  let hasLlm = false;
95	  let hasMcp = false;
96	  for (const { kind } of Object.values(credentials)) {
97	    if (kind === 'api-key' || kind.startsWith('anthropic-')) hasLlm = true;
98	    else if (kind.startsWith('mcp-')) hasMcp = true;
99	  }
100	  if (hasLlm) return 'llm';
101	  if (hasMcp) return 'mcp';
102	  return 'other';
103	}
104	
105	/**
106	 * Translate the listener's internal `blocked` string vocabulary into the
107	 * bus event's `blockedReason` enum. Returns `undefined` if the audit entry
108	 * isn't a block (or carries an unrecognized reason — we don't fabricate).
109	 *
110	 * Vocabulary:
111	 * - `domain_denied: …`     → `'allowlist'`  (allowlist miss)
112	 * - `Blocked: …` (BlockedIPError) → `'private-ip'`
113	 * - `canary_detected`      → `'canary'`
114	 * - `tls_error: …`         → `'tls-error'`
115	 * - anything else (`invalid_target`, `Proxy error: …`) → undefined
116	 *   (these surface as a non-2xx `status` instead).
117	 */
118	function mapBlockedReason(
119	  blocked: string | undefined,
120	): HttpEgressEvent['blockedReason'] | undefined {
121	  if (blocked === undefined) return undefined;
122	  if (blocked.startsWith('domain_denied:')) return 'allowlist';
123	  if (blocked.startsWith('Blocked:')) return 'private-ip';
124	  if (blocked === 'canary_detected') return 'canary';
125	  if (blocked.startsWith('tls_error:')) return 'tls-error';
126	  return undefined;
127	}
128	
129	/**
130	 * Parse an audit entry's `url` into `{ host, path }` for the bus event.
131	 *
132	 * Two URL shapes the listener hands us:
133	 * - HTTP forward: an absolute URL like `http://api.example.com/foo` (or
134	 *   the raw `req.url` path, if the bridge passed a relative form). The
135	 *   `URL` constructor handles both with a fallback base.
136	 * - CONNECT: a `host:port` target like `api.anthropic.com:443`. There's
137	 *   no path on a CONNECT — set `'/'` so subscribers always see a string.
138	 *
139	 * For CONNECT entries (`method === 'CONNECT'`) the URL parser would treat
140	 * `api.anthropic.com:443` as a protocol-relative URL and fail; we
141	 * special-case the split.
142	 */
143	function parseHostPath(method: string, url: string): { host: string; path: string } {
144	  if (method === 'CONNECT') {
145	    // CONNECT target is `host:port`. Split on the last `:` so IPv6 literals
146	    // like `[::1]:443` still work — though Phase 1a's bridge only emits
147	    // hostnames (no IPv6 brackets).
148	    const lastColon = url.lastIndexOf(':');
149	    const host = lastColon === -1 ? url : url.slice(0, lastColon);
150	    return { host, path: '/' };
151	  }
152	  try {
153	    const parsed = new URL(
154	      url.startsWith('http://') || url.startsWith('https://')
155	        ? url
156	        : `http://placeholder${url.startsWith('/') ? url : '/' + url}`,
157	    );
158	    // For the placeholder fallback, host is meaningless — return empty so
159	    // subscribers don't think it was a real hostname. (This branch is rare:
160	    // the HTTP forwarding path always builds an absolute URL before logging.)
161	    const host = parsed.hostname === 'placeholder' ? '' : parsed.hostname;
162	    return { host, path: parsed.pathname + parsed.search };
163	  } catch {
164	    return { host: '', path: url };
165	  }
166	}
167	
168	export interface CredentialProxyConfig {
169	  listen: { kind: 'unix'; path: string } | { kind: 'tcp'; host?: string; port?: number };
170	  caDir?: string;
171	}
172	
173	// ── Hook payload types (Phase 1a — Task 11 may revise audit shape) ────
174	
175	interface OpenSessionInput {
176	  sessionId: string;
177	  userId: string;
178	  agentId: string;
179	  /** Hostnames this session is allowed to reach (exact match). */
180	  allowlist: string[];
181	  /** envName → { ref to credentials store, kind hint for downstream policy }. */
182	  credentials: Record<string, { ref: string; kind: string }>;
183	  /** Hostnames whose CONNECT bypasses MITM (cert-pinning escape hatch). */
184	  bypassMITM?: string[];
185	  /** Optional canary token; chunks containing it trip a 403. */
186	  canaryToken?: string;
187	  /** IPs exempt from the private-range block — test-only escape hatch. */
188	  allowedIPs?: string[];
189	}
190	
191	interface OpenSessionOutput {
192	  /** Endpoint the bridge / sandbox bootstrap should point HTTP(S)_PROXY at. */
193	  proxyEndpoint: string;
194	  /** Root CA cert PEM the sandbox must trust to validate MITM leaf certs. */
195	  caCertPem: string;
196	  /** envName → opaque placeholder token (`ax-cred:<32-hex>`). */
197	  envMap: Record<string, string>;
198	}
199	
200	interface CloseSessionInput {
201	  sessionId: string;
202	}
203	
204	interface RotateSessionInput {
205	  sessionId: string;
206	}
207	
208	interface RotateSessionOutput {
209	  /** Fresh envName → placeholder map. Old placeholders no longer match. */
210	  envMap: Record<string, string>;
211	}
212	
213	/** envName → original credential ref (so rotate can re-resolve). */
214	type SessionCredentialRefs = Record<string, { ref: string; kind: string }>;
215	
216	// ── Helpers ──────────────────────────────────────────────────────────
217	
218	function buildEndpointString(
219	  listen: CredentialProxyConfig['listen'],
220	  listener: ProxyListener,
221	): string {
222	  if (listen.kind === 'unix') {
223	    return `unix://${listen.path}`;
224	  }
225	  const host = listen.host ?? '127.0.0.1';
226	  return `tcp://${host}:${listener.port}`;
227	}
228	
229	// ── Plugin ───────────────────────────────────────────────────────────
230	
231	export function createCredentialProxyPlugin(config: CredentialProxyConfig): Plugin {
232	  // Capture the listener and shared mutable state in closure — the plugin's
233	  // hook handlers and shutdown all need access. They're assigned during
234	  // init(); accessing before init() throws via the explicit `if (!ready)`
235	  // guards inside each handler (handlers can't fire until init completes
236	  // because they're registered there).
237	  let listener: ProxyListener | undefined;
238	  let sessions: Map<string, SessionConfig> | undefined;
239	  let registry: SharedCredentialRegistry | undefined;
240	  let caCertPem: string | undefined;
241	  let endpointString: string | undefined;
242	  // Per-session credential refs — populated on open, read on rotate, dropped
243	  // on close. Lives on the plugin instance (not on SessionConfig) because it's
244	  // private state used only for rotation; the listener never reads it.
245	  const sessionCredentialRefs = new Map<string, SessionCredentialRefs>();
246	
247	  const caDir = config.caDir ?? join(homedir(), '.ax', 'proxy-ca');
248	
249	  return {
250	    manifest: {
251	      name: PLUGIN_NAME,
252	      version: '0.0.0',
253	      registers: ['proxy:open-session', 'proxy:rotate-session', 'proxy:close-session'],
254	      calls: ['credentials:get'],
255	      subscribes: [],
256	    },
257	
258	    async init({ bus }) {
259	      // 1. Get/create the MITM CA.
260	      const ca = await getOrCreateCA(caDir);
261	      caCertPem = ca.cert;
262	
263	      // 2. Build the per-process registry + session-config Map. Both are
264	      //    shared by reference with the listener, so future mutations
265	      //    flow through without setter methods.
266	      sessions = new Map<string, SessionConfig>();
267	      registry = new SharedCredentialRegistry();
268	
269	      // 3. Start the listener with an `onAudit` that translates each
270	      //    listener-internal `ProxyAuditEntry` into the public
271	      //    `event.http-egress` payload and fires it on the bus.
272	      //
273	      //    The listener calls onAudit synchronously from inside HTTP/CONNECT
274	      //    handlers; we intentionally don't await `bus.fire` here. Subscriber
275	      //    failures are caught + logged inside HookBus.fire (the contract),
276	      //    so a misbehaving subscriber can't break the proxy. We swallow the
277	      //    returned promise rejection (which would only fire if `fire` itself
278	      //    throws — currently impossible) so an unhandled rejection can't
279	      //    take the process down.
280	      const onAudit = (entry: ProxyAuditEntry): void => {
281	        const { host, path } = parseHostPath(entry.method, entry.url);
282	        const blockedReason = mapBlockedReason(entry.blocked);
283	        const payload: HttpEgressEvent = {
284	          sessionId: entry.sessionId ?? '',
285	          userId: entry.userId ?? '',
286	          method: entry.method,
287	          host,
288	          path,
289	          status: entry.status,
290	          requestBytes: entry.requestBytes,
291	          responseBytes: entry.responseBytes,
292	          durationMs: entry.durationMs,
293	          credentialInjected: entry.credentialInjected ?? false,
294	          classification: entry.classification ?? 'other',
295	          timestamp: Date.now(),
296	        };
297	        if (blockedReason !== undefined) payload.blockedReason = blockedReason;
298	
299	        // Build a synthetic AgentContext for the fire — the listener's data
300	        // events run far from the original request context. sessionId/userId
301	        // come from the matching session (or empty strings on allowlist miss).
302	        const fireCtx = makeAgentContext({
303	          sessionId: payload.sessionId,
304	          userId: payload.userId,
305	          agentId: '',
306	        });
307	
308	        bus.fire('event.http-egress', fireCtx, payload).catch((err: unknown) => {
309	          // HookBus.fire isolates subscriber throws — this catch only fires
310	          // if HookBus itself throws, which it currently doesn't. Log to the
311	          // synthetic context's logger so the failure is visible without
312	          // crashing the proxy.
313	          fireCtx.logger.error('http_egress_fire_failed', {
314	            err: err instanceof Error ? err : new Error(String(err)),
315	          });
316	        });
317	      };
318	
319	      listener = await startProxyListener({
320	        listen: config.listen,
321	        registry,
322	        sessions,
323	        ca,
324	        onAudit,
325	      });
326	      endpointString = buildEndpointString(config.listen, listener);
327	
328	      // 4a. proxy:open-session — resolve credentials, register placeholders,
329	      //     persist session config, return endpoint + CA + envMap.
330	      bus.registerService<OpenSessionInput, OpenSessionOutput>(
331	        'proxy:open-session',
332	        PLUGIN_NAME,
333	        async (ctx: AgentContext, input) => {
334	          if (!sessions || !registry || !endpointString || !caCertPem) {
335	            // Should be unreachable — handler can't fire before init().
336	            throw new PluginError({
337	              code: 'not-initialized',
338	              plugin: PLUGIN_NAME,
339	              message: 'credential-proxy plugin handler invoked before init completed',
340	            });
341	          }
342	
343	          // Resolve every credential ref via credentials:get (Phase 3 shape:
344	          // `({ ref, userId }) → string`).
345	          const map = new CredentialPlaceholderMap();
346	          for (const [envName, { ref }] of Object.entries(input.credentials)) {
347	            const value = await bus.call<
348	              { ref: string; userId: string },
349	              string
350	            >('credentials:get', ctx, { ref, userId: input.userId });
351	            map.register(envName, value);
352	          }
353	
354	          // Register the placeholder map with the shared registry so the
355	          // MITM substitution path can find it.
356	          registry.register(input.sessionId, map);
357	
358	          // Persist the session config — the listener iterates this on every
359	          // request to gate egress, run SSRF checks, and decide MITM-vs-bypass.
360	          //
361	          // Also stamp sessionId/userId/classification so the listener can
362	          // attribute audit entries to the right session for the
363	          // event.http-egress emission.
364	          const sessionConfig: SessionConfig = {
365	            allowlist: new Set(input.allowlist),
366	            sessionId: input.sessionId,
367	            userId: input.userId,
368	            classification: classifyCredentials(input.credentials),
369	          };
370	          if (input.allowedIPs && input.allowedIPs.length > 0) {
371	            sessionConfig.allowedIPs = new Set(input.allowedIPs);
372	          }
373	          if (input.bypassMITM && input.bypassMITM.length > 0) {
374	            sessionConfig.bypassMITM = new Set(input.bypassMITM);
375	          }
376	          if (input.canaryToken) {
377	            sessionConfig.canaryToken = input.canaryToken;
378	          }
379	          sessions.set(input.sessionId, sessionConfig);
380	
381	          // Remember the credential refs so proxy:rotate-session can
382	          // re-resolve. Shallow-clone to insulate against caller mutation.
383	          const refsCopy: SessionCredentialRefs = {};
384	          for (const [envName, { ref, kind }] of Object.entries(input.credentials)) {
385	            refsCopy[envName] = { ref, kind };
386	          }
387	          sessionCredentialRefs.set(input.sessionId, refsCopy);
388	
389	          return {
390	            proxyEndpoint: endpointString,
391	            caCertPem,
392	            envMap: map.toEnvMap(),
393	          };
394	        },
395	      );
396	
397	      // 4b. proxy:rotate-session — re-resolve every credential ref via
398	      //     credentials:get and update the EXISTING session map's values
399	      //     in place. The placeholder tokens are unchanged (Phase 3 I11) —
400	      //     a fresh placeholder would invalidate the running sandbox's env,
401	      //     since the SDK already read it at startup and won't re-read.
402	      //     Future requests substitute the refreshed value under the same
403	      //     `ax-cred:<hex>` token; substitution stays seamless.
404	      bus.registerService<RotateSessionInput, RotateSessionOutput>(
405	        'proxy:rotate-session',
406	        PLUGIN_NAME,
407	        async (ctx: AgentContext, { sessionId }) => {
408	          if (!registry || !sessions) {
409	            throw new PluginError({
410	              code: 'not-initialized',
411	              plugin: PLUGIN_NAME,
412	              message: 'credential-proxy plugin handler invoked before init completed',
413	            });
414	          }
415	          const refs = sessionCredentialRefs.get(sessionId);
416	          const sess = sessions.get(sessionId);
417	          const existingMap = registry.get(sessionId);
418	          if (!refs || !sess || !existingMap) {
419	            throw new PluginError({
420	              code: 'unknown-session',
421	              plugin: PLUGIN_NAME,
422	              message: `session ${sessionId} not open`,
423	            });
424	          }
425	          // SessionConfig.userId is optional in the listener's type, but
426	          // every code path that registers a SessionConfig in this plugin
427	          // sets it from the open-session input. Treat missing as a bug.
428	          if (sess.userId === undefined) {
429	            throw new PluginError({
430	              code: 'session-missing-user',
431	              plugin: PLUGIN_NAME,
432	              message: `session ${sessionId} has no userId — refusing to rotate`,
433	            });
434	          }
435	          // userId is pulled from the session config (set at open time), NOT
436	          // from ctx — rotation happens for the same session whose owner is
437	          // already pinned. Using ctx.userId here would let a caller from a
438	          // different user-context resolve someone else's credentials.
439	          const userId = sess.userId;
440	          for (const [envName, { ref }] of Object.entries(refs)) {
441	            const value = await bus.call<
442	              { ref: string; userId: string },
443	              string
444	            >('credentials:get', ctx, { ref, userId });
445	            const placeholder = existingMap.updateValue(envName, value);
446	            if (placeholder === undefined) {
447	              // Should be impossible — open-session registered every envName
448	              // in `refs`. If it ever happens, surface clearly rather than
449	              // silently leaving stale values in the substitution table.
450	              throw new PluginError({
451	                code: 'placeholder-not-registered',
452	                plugin: PLUGIN_NAME,
453	                message: `rotate-session: '${envName}' was never registered for session ${sessionId}`,
454	              });
455	            }
456	          }
457	          return { envMap: existingMap.toEnvMap() };
458	        },
459	      );
460	
461	      // 4c. proxy:close-session — deregister registry + drop session config.
462	      bus.registerService<CloseSessionInput, Record<string, never>>(
463	        'proxy:close-session',
464	        PLUGIN_NAME,
465	        async (_ctx, { sessionId }) => {
466	          if (!sessions || !registry) {
467	            throw new PluginError({
468	              code: 'not-initialized',
469	              plugin: PLUGIN_NAME,
470	              message: 'credential-proxy plugin handler invoked before init completed',
471	            });
472	          }
473	          registry.deregister(sessionId);
474	          sessions.delete(sessionId);
475	          sessionCredentialRefs.delete(sessionId);
476	          return {};
477	        },
478	      );
479	    },
480	
481	    shutdown() {
482	      if (listener) {
483	        listener.stop();
484	        listener = undefined;
485	      }
486	    },
487	  };
488	}
