131	   * to `proxy:open-session`, which resolves each ref via `credentials:get`
132	   * and registers a `ax-cred:<hex>` placeholder in the listener's
133	   * substitution registry. The runner only ever sees the placeholder
134	   * inside its env map (I1: real credentials never enter the sandbox).
135	   */
136	  requiredCredentials?: Record<string, { ref: string; kind: string }>;
137	}
