142	// proxy:* shapes — duplicated structurally per I2. The orchestrator does
143	// NOT import from @ax/credential-proxy; calls flow through bus.call.
144	interface ProxyOpenSessionInput {
145	  sessionId: string;
146	  userId: string;
147	  agentId: string;
148	  /** Hostnames this session may reach (exact match). */
149	  allowlist: string[];
150	  /** envName → { ref to credentials store, kind hint for downstream policy }. */
151	  credentials: Record<string, { ref: string; kind: string }>;
152	}
