176	// (no cross-plugin imports). The orchestrator reads `activeSessionId` to
177	// decide whether to route the message into an existing sandbox session or
178	// open a fresh one, and binds the conversation row on either path.
179	interface ConversationsGetInput {
180	  conversationId: string;
181	  userId: string;
182	}
