244	  /** TCP endpoint (subprocess sandbox), e.g. 'http://127.0.0.1:54321'. */
245	  endpoint?: string;
246	  /** Unix socket path (k8s sandbox), e.g. '/var/run/ax/proxy.sock'. */
247	  unixSocketPath?: string;
248	  /**
249	   * MITM CA certificate PEM bytes. Sandbox runtime writes this to disk
250	   * inside the sandbox and points NODE_EXTRA_CA_CERTS / SSL_CERT_FILE at
251	   * the path. The orchestrator never knows the path.
252	   */
253	  caCertPem: string;
254	  /**
255	   * Env injected by `proxy:open-session`. Maps env-var names (e.g.
256	   * `ANTHROPIC_API_KEY`) to `ax-cred:<hex>` placeholders the proxy
257	   * recognizes. Sandbox-subprocess merges these into the runner env.
258	   */
259	  envMap: Record<string, string>;

