1	// ---------------------------------------------------------------------------
2	// @ax/mcp-client plugin factory (Task 13).
3	//
4	// This is the centerpiece of the package. On init we:
5	//
6	//   1. Read MCP server configs from storage (Task 8's `loadConfigs`).
7	//   2. For each enabled config, open an `McpConnection` (Task 10/11) and
8	//      list its tools.
9	//   3. Namespace the tools (Task 12's `namespaceTools`) so two servers
10	//      advertising `read_file` don't collide in the dispatcher's catalog.
11	//   4. Register each namespaced descriptor with `tool:register`.
12	//   5. Register a `tool:execute:${namespacedName}` service hook per tool
13	//      that routes back to `connection.callTool(originalName, input)`.
14	//
15	// Why the per-tool service registration is a DYNAMIC exception:
16	//
17	// Every other plugin's `manifest.registers` lists hook names statically so
18	// the bus can validate the call graph before anything runs. But the set of
19	// `tool:execute:${name}` hooks depends on what MCP servers actually advertise
20	// at runtime — we don't know the tool list until after `connect()` +
21	// `listTools()`. So `registers: []` is literal: we add hooks during init
22	// instead, mirroring the dynamic pattern used by the legacy tool-dispatcher
23	// and documented in `@ax/ipc-server`'s tool-execute-host handler:
24	// packages/ipc-server/src/handlers/tool-execute-host.ts:37.
25	//
26	// Failure model:
27	//
28	//  - A single server failing to connect MUST NOT take the plugin down.
29	//    We log a warning and skip it; its tools simply don't appear in the
30	//    catalog. The reconnect backoff in `McpConnection` may still bring
31	//    it back later (post-MVP: we'd then register its tools lazily — for
32	//    now Week 6.5e ships with static-at-init-time tool wiring).
33	//  - `MCP_SERVER_UNAVAILABLE` from `callTool` is translated to a tool-error
34	//    result (`isError:true` + text content). The model sees a tool failure
35	//    it can reason about; the chat keeps going.
36	// ---------------------------------------------------------------------------
37	
38	import {
39	  PluginError,
40	  makeAgentContext,
41	  type AgentContext,
42	  type Plugin,
43	  type ToolCall,
44	} from '@ax/core';
45	import { registerAdminMcpRoutes } from './admin-routes.js';
46	import { loadConfigs, type McpServerConfig } from './config.js';
47	import { McpConnection } from './connection.js';
48	import { namespaceTools } from './tool-names.js';
49	import {
50	  createTransport,
51	  type BusLike,
52	  type CreateTransportOptions,
53	  type McpClientTransport,
54	} from './transports.js';
55	
56	const PLUGIN_NAME = '@ax/mcp-client';
57	
58	interface HandlerEntry {
59	  connection: McpConnection;
60	  originalName: string;
61	}
62	
63	export interface CreateMcpClientPluginOptions {
64	  /**
65	   * Test seam: override transport construction. Production callers should
66	   * leave this undefined so `createTransport` (stdio / streamable-http /
67	   * sse) is used. Tests inject pre-linked `InMemoryTransport` pairs so they
68	   * can exercise the full plugin without spawning subprocesses or opening
69	   * sockets.
70	   */
71	  transportFactory?: (opts: {
72	    config: McpServerConfig;
73	    bus: BusLike;
74	    ctx: AgentContext;
75	  }) => Promise<McpClientTransport>;
76	  /**
77	   * If true, mount the /admin/mcp-servers routes. Default: false. The
78	   * agents plugin always mounts admin routes; this plugin gates on the
79	   * flag because @ax/mcp-client is also loaded in CLI / sandbox-side
80	   * contexts (no @ax/http-server, no @ax/auth) and we don't want those
81	   * boots to fail. The multi-tenant preset sets it.
82	   */
83	  mountAdminRoutes?: boolean;
84	  /**
85	   * Test seam for the /test endpoint. Lets a test inject a fake
86	   * transport (in-memory pair) so the test endpoint exercises connect
87	   * + listTools without an actual outbound network call.
88	   */
89	  testTransportFactory?: (
90	    opts: CreateTransportOptions,
91	  ) => Promise<McpClientTransport>;
92	  /**
93	   * Test seam to shorten the /test timeout. Defaults to 30 s in production.
94	   */
95	  testTimeoutMs?: number;
96	}
97	
98	/**
99	 * Build the @ax/mcp-client plugin. Intended to be added to the bootstrap
100	 * plugin list after @ax/storage-sqlite + @ax/credentials + @ax/tool-dispatcher,
101	 * since all three produce hooks this plugin calls during init.
102	 */
103	export function createMcpClientPlugin(opts: CreateMcpClientPluginOptions = {}): Plugin {
104	  const mountAdminRoutes = opts.mountAdminRoutes === true;
105	  const unregisterRoutes: Array<() => void> = [];
106	  // calls list is built once at construction so the manifest is stable
107	  // and matches what init actually uses.
108	  const calls: string[] = [
109	    'tool:register',
110	    'storage:get',
111	    'storage:set',
112	    'credentials:get',
113	  ];
114	  if (mountAdminRoutes) {
115	    calls.push('http:register-route', 'auth:require-user');
116	  }
117	  return {
118	    manifest: {
119	      // `registers: []` is deliberate — see file banner. The per-tool
120	      // `tool:execute:${name}` service hooks are registered dynamically
121	      // inside init based on what the configured MCP servers advertise.
122	      name: PLUGIN_NAME,
123	      version: '0.0.0',
124	      registers: [],
125	      calls,
126	      subscribes: [],
127	    },
128	    async init({ bus }) {
129	      // Synthesize a minimal init-time ctx: the hooks we call during init
130	      // (`storage:get`, `storage:set`, `credentials:get`, `tool:register`)
131	      // don't read session/agent/user identity, they just need a AgentContext
132	      // envelope (and a logger). Mirrors @ax/test-harness/test-host-tool.ts.
133	      const initCtx = makeAgentContext({
134	        sessionId: 'init',
135	        agentId: PLUGIN_NAME,
136	        userId: 'init',
137	      });
138	
139	      const configs = await loadConfigs(bus, initCtx);
140	
141	      // Open connections in parallel — 5 MCP servers shouldn't serialize 5
142	      // round-trip connects during startup. Tool registration happens
143	      // sequentially afterwards so the dispatcher's catalog (single source
144	      // of truth, invariant I4) gets writes in a deterministic order.
145	      const connectResults = await Promise.all(
146	        configs
147	          .filter((c) => c.enabled)
148	          .map(async (config) => {
149	            // HTTPS-by-default: if an HTTP/SSE config points at plain http://,
150	            // warn so operators know secrets traverse the wire in cleartext.
151	            // The config still works (Task 8 accepts http:// for dev loops).
152	            if (
153	              (config.transport === 'streamable-http' || config.transport === 'sse') &&
154	              config.url.startsWith('http://')
155	            ) {
156	              initCtx.logger.warn('mcp_plain_http_transport', {
157	                serverId: config.id,
158	                hint: 'secrets will traverse the wire in cleartext; prefer https://',
159	              });
160	            }
161	            const connection = new McpConnection({
162	              config,
163	              bus,
164	              ctx: initCtx,
165	              ...(opts.transportFactory !== undefined
166	                ? { transportFactory: opts.transportFactory }
167	                : {}),
168	            });
169	            try {
170	              await connection.connect();
171	            } catch (err) {
172	              // Don't fail plugin init — other servers should still come
173	              // up. The reconnect backoff in McpConnection will continue
174	              // retrying this one in the background (though its tools
175	              // won't make it into the catalog until a post-MVP lazy-
176	              // registration path lands).
177	              initCtx.logger.warn('mcp_init_connect_failed', {
178	                serverId: config.id,
179	                err: err instanceof Error ? err.message : String(err),
180	              });
181	              return null;
182	            }
183	            const listed = await connection.listTools();
184	            if (!listed.ok) {
185	              initCtx.logger.warn('mcp_init_list_failed', {
186	                serverId: config.id,
187	                code: listed.code,
188	                reason: listed.reason,
189	              });
190	              return null;
191	            }
192	            return { config, connection, tools: listed.tools };
193	          }),
194	      );
195	
196	      const handlerByName = new Map<string, HandlerEntry>();
197	
198	      for (const result of connectResults) {
199	        if (result === null) continue;
200	        const { config, connection, tools } = result;
201	        const { descriptors, nameMap } = namespaceTools(config.id, tools);
202	        for (const descriptor of descriptors) {
203	          await bus.call('tool:register', initCtx, descriptor);
204	          const originalName = nameMap.get(descriptor.name);
205	          if (originalName === undefined) {
206	            // Unreachable if namespaceTools honors its own invariants, but
207	            // cheap to guard and expensive to debug otherwise.
208	            throw new PluginError({
209	              code: 'name-map-mismatch',
210	              plugin: PLUGIN_NAME,
211	              message: `internal: descriptor '${descriptor.name}' missing from nameMap`,
212	            });
213	          }
214	          handlerByName.set(descriptor.name, { connection, originalName });
215	        }
216	      }
217	
218	      // Mount /admin/mcp-servers[/:id][/test] last — the bus calls inside
219	      // their handlers reach storage / credentials / auth, which are
220	      // already registered (auth comes from the auth plugin via the
221	      // manifest's `calls` edge). When mountAdminRoutes is false we
222	      // skip this entirely so single-process / sandbox contexts that
223	      // don't load @ax/http-server still boot.
224	      if (mountAdminRoutes) {
225	        const opts2: {
226	          testTransportFactory?: (
227	            o: CreateTransportOptions,
228	          ) => Promise<McpClientTransport>;
229	          testTimeoutMs?: number;
230	        } = {};
231	        if (opts.testTransportFactory !== undefined) {
232	          opts2.testTransportFactory = opts.testTransportFactory;
233	        }
234	        if (opts.testTimeoutMs !== undefined) {
235	          opts2.testTimeoutMs = opts.testTimeoutMs;
236	        }
237	        const unregisters = await registerAdminMcpRoutes(bus, initCtx, opts2);
238	        unregisterRoutes.push(...unregisters);
239	      }
240	
241	      // Dynamic tool:execute:${name} registration. See file banner for why
242	      // this lives in init instead of manifest.registers.
243	      for (const [namespacedName, entry] of handlerByName) {
244	        const hookName = `tool:execute:${namespacedName}`;
245	        bus.registerService<ToolCall, { output: unknown }>(
246	          hookName,
247	          PLUGIN_NAME,
248	          async (_ctx, call) => {
249	            const result = await entry.connection.callTool(
250	              entry.originalName,
251	              (call as { input: unknown }).input,
252	            );
253	            if (result.ok) {
254	              return { output: result.result };
255	            }
256	            // Server is unavailable. Wrap as a tool-error result so the
257	            // model sees a tool failure rather than a chat-terminating
258	            // exception. Shape (`isError:true` + content) matches what
259	            // providers already render for server-reported tool errors.
260	            return {
261	              output: {
262	                isError: true,
263	                content: [
264	                  {
265	                    type: 'text',
266	                    text: `MCP server '${entry.connection.serverId}' unavailable: ${result.reason}`,
267	                  },
268	                ],
269	              },
270	            };
271	          },
272	        );
273	      }
274	    },
275	    async shutdown() {
276	      // Drop admin routes so a re-init in tests doesn't trip duplicate-
277	      // route. The http-server's unregister is idempotent; we still
278	      // wrap in try/catch so a transport-level error doesn't abort the
279	      // rest of the shutdown loop.
280	      while (unregisterRoutes.length > 0) {
281	        const fn = unregisterRoutes.pop();
282	        try {
283	          fn?.();
284	        } catch {
285	          // best-effort
286	        }
287	      }
288	    },
289	  };
290	}
291	
292	// Re-export createTransport for downstream composition tests. The default
293	// (production) transport factory path runs through it when opts.transportFactory
294	// is omitted — exposing it here lets acceptance tests (Task 18) assert that
295	// the real factory is being used without poking at private plugin state.
296	export { createTransport };
