1	// ---------------------------------------------------------------------------
2	// SKILL.md YAML frontmatter parser (Phase 3 Slice 8).
3	//
4	// Skills follow Anthropic's claude-skills convention: a YAML
5	// frontmatter block at the top of SKILL.md, fenced by `---` lines,
6	// followed by markdown body. Required fields:
7	//   name        - non-empty string
8	//   description - non-empty string
9	//
10	// Other fields (e.g. version, category) are permitted but not
11	// validated. The parser is intentionally narrow: we check the shape
12	// the host needs to know about a skill exists, no more.
13	//
14	// Untrusted-input discipline: SKILL.md content comes from the agent
15	// (model output -> tool call -> workspace write). Treat as adversarial:
16	//   - Decode bytes as UTF-8 STRICT (no replacement chars). Non-UTF-8
17	//     bytes are rejected loud rather than silently coerced.
18	//   - YAML parser is js-yaml's `load` (the safe schema by default,
19	//     no js-functions, no class instantiation, no tag escapes that
20	//     could trigger code execution).
21	//   - We do not interpolate fields into shell, paths, HTML, SQL, or
22	//     any other context that would care about the bytes - we just
23	//     ack the shape and move on.
24	// ---------------------------------------------------------------------------
25	
26	import { load as yamlLoad, YAMLException } from 'js-yaml';
27	
28	const FRONTMATTER_FENCE = /^---\n([\s\S]*?)\n---(\n|$)/;
29	
30	export interface FrontmatterFields {
31	  name: string;
32	  description: string;
33	}
34	
35	export type FrontmatterResult =
36	  | { ok: true; fields: FrontmatterFields }
37	  | { ok: false; reason: string };
38	
39	/**
40	 * Parse SKILL.md frontmatter from a UTF-8 string.
41	 *
42	 * Pure function. No filesystem, no network, no process spawn - given
43	 * the same input, returns the same result. Easy to fuzz; easy to
44	 * reason about.
45	 */
46	export function parseFrontmatter(text: string): FrontmatterResult {
47	  const m = FRONTMATTER_FENCE.exec(text);
48	  if (m === null) {
49	    return { ok: false, reason: 'no frontmatter block' };
50	  }
51	  const body = m[1] ?? '';
52	  let parsed: unknown;
53	  try {
54	    // js-yaml's default `load` uses the safe schema (no js-functions,
55	    // no class instantiation). Anonymous values (e.g., `: bad`) throw
56	    // YAMLException, which we catch and surface as a clean reason.
57	    parsed = yamlLoad(body);
58	  } catch (err) {
59	    if (err instanceof YAMLException) {
60	      return { ok: false, reason: `invalid YAML in frontmatter: ${err.reason}` };
61	    }
62	    return { ok: false, reason: `invalid YAML in frontmatter` };
63	  }
64	  if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
65	    return {
66	      ok: false,
67	      reason: 'frontmatter must be a YAML mapping (object), not array/scalar',
68	    };
69	  }
70	  const obj = parsed as Record<string, unknown>;
71	  const name = obj['name'];
72	  const description = obj['description'];
73	  if (typeof name !== 'string' || name.length === 0) {
74	    return { ok: false, reason: 'frontmatter missing required field: name' };
75	  }
76	  if (typeof description !== 'string' || description.length === 0) {
77	    return {
78	      ok: false,
