  allChanges = await walkBundleChanges({
    repoPath: scratch.repoPath,
    baselineCommit: scratch.baselineCommit,
  });
} catch (err) {
  logInternalError(ctx.logger, 'workspace.commit-notify', err);
  return internalError();
}

// Filter to .ax/** for the pre-apply hook. Subscribers (skill
// validator, future identity validator) only see agent-managed
// memory; user-code changes are not policy-checked.
const axChanges = filterToAx(allChanges);

// ---- pre-apply: subscribers can transform or veto ----
const pre = await bus.fire<{
  changes: FileChange[];
  parent: WorkspaceVersion | null;
  reason: string;
}>(
  'workspace:pre-apply',
  ctx,
  { changes: axChanges, parent, reason },
);
if (pre.rejected) {
  const body = { accepted: false as const, reason: pre.reason };
  const checked = WorkspaceCommitNotifyResponseSchema.safeParse(body);
  if (!checked.success) {
    logInternalError(
      ctx.logger,
      'workspace.commit-notify',
      new Error(`response shape drift (rejected): ${checked.error.message}`),
    );
    return internalError();
  }
  return { status: 200, body: checked.data };
}

// ---- apply: workspace:apply-bundle is required (the export-
//      baseline-bundle gate above already rejected backends that
//      don't implement the bundle wire — apply-bundle and export-
//      baseline-bundle ship together as the Phase 3 backend
//      contract).
let applied: WorkspaceApplyOutput;
try {
  const out = await bus.call<
    WorkspaceApplyBundleInput,
    WorkspaceApplyBundleOutput
  >('workspace:apply-bundle', ctx, {
    bundleBytes,
    baselineCommit: scratch.baselineCommit,
    parent,
    reason,
  });
  applied = out;
} catch (err) {
  if (err instanceof PluginError && err.code === 'parent-mismatch') {
    const body = {
      accepted: false as const,
      reason: `parent-mismatch: ${err.message}`,
    };
    const checked = WorkspaceCommitNotifyResponseSchema.safeParse(body);
    if (!checked.success) {
      logInternalError(
        ctx.logger,
        'workspace.commit-notify',
        new Error(
          `response shape drift (parent-mismatch): ${checked.error.message}`,
        ),
      );
      return internalError();
    }
    return { status: 200, body: checked.data };
  }
  // Other errors bubble to the dispatcher's catch-all (sanitized 500).
  throw err;
}

// ---- applied: observers (audit, canary, future analytics) get
// the host-side delta with its lazy fetchers intact. ----

import type { FileChange } from '@ax/core';

// ---------------------------------------------------------------------------
// `.ax/**` filter — pure path predicate.
//
// Phase 3 contract: workspace:pre-apply subscribers see ONLY agent-managed
// project memory (`.ax/**`). Subscribers like the skill validator
// (Slice 8) decide allow/veto on this filtered subset; workspace:apply
// then receives the FULL change set and lands everything.
//
// Rationale: pre-apply checks are policy. Policy applies to the agent's
// own project state — its skills, its memory, its identity files —
// not to the user's source code. A model writing `src/main.ts` doesn't
// trip the skill validator; a model writing `.ax/skills/foo/SKILL.md`
// does. Keeping the filter at this single chokepoint means future
// validators (identity, skill schema, etc.) all see the same scope and
// can't accidentally key off paths outside `.ax/`.
//
// Why startsWith and not picomatch: the rule is intentionally rigid —
// "anything under .ax/." There's no glob nuance to express, no
// per-validator override knob, no escape hatch. A literal prefix check
// keeps the policy obvious and impossible to misconfigure.
// ---------------------------------------------------------------------------

const AX_PREFIX = '.ax/';

export function filterToAx(changes: readonly FileChange[]): FileChange[] {
  return changes.filter((c) => c.path.startsWith(AX_PREFIX));
}

