  // The test calls openSession via the existing helper / mock setup.
  // Assert: env.HOME is defined, != process.env.HOME, and CLAUDE_CONFIG_DIR is
  // path.join(env.HOME, '.ax', 'session').
  // Assert: $CLAUDE_CONFIG_DIR/skills/ exists on disk before the runner is spawned.
});

it('cleans up the per-session HOME on session close', async () => {
  // After closeSession, the homeDir should no longer exist.
});

it('symlinks <workspace>/.claude/skills to ../.ax/skills', async () => {
  // Assert: readlink returns '../.ax/skills'.
  // Assert: the resolved target equals path.join(workspaceRoot, '.ax', 'skills').
});

it('does not symlink the parent .claude/ directory — only .claude/skills/', async () => {
  // .claude/ itself should be a regular directory (not a symlink).
  // Only .claude/skills/ should be the symlink.
});

it('handles re-entry on a workspace where .claude/skills already exists', async () => {
  // Pre-create a dangling symlink or stale file at <workspace>/.claude/skills.
  // openSession should overwrite it cleanly (no EEXIST).
});
```

Match the calling convention of the existing test file (might use `vi.mock`, `setupTestSandbox`, or similar).

### Step 4: Run tests, expect failure

```bash
pnpm test --filter @ax/sandbox-subprocess
```

### Step 5: Implement

In `open-session.ts`, after socketDir is allocated but BEFORE sessionEnv is built, add the home + skills + symlink setup. Sketch:

```typescript
import * as path from 'node:path';
import { promises as fs } from 'node:fs';

// I-P0-3: per-session HOME, isolated from the host user's home.
// Reuses the same per-session tempdir root as the IPC socket; cleanup
// piggybacks on the existing socketDir cleanup path.
const homeDir = path.join(socketDir, 'home');
const claudeConfigDir = path.join(homeDir, '.ax', 'session');
const installedSkillsDir = path.join(claudeConfigDir, 'skills');
await fs.mkdir(installedSkillsDir, { recursive: true, mode: 0o755 });
// Phase 1 will materialize installed-skill bodies here. For Phase 0
// the directory is empty but must exist so the SDK's discovery walk
// doesn't ENOENT. chmod 0555 only after Phase 1 writes — in Phase 0
// the dir stays 0755 (writable) since nothing writes here yet.

// I-P0-4: narrow symlink. Workspace `.claude/` must exist as a real
// directory; only the `skills` child is symlinked into `.ax/skills/`.
const workspaceClaudeDir = path.join(input.workspaceRoot, '.claude');
await fs.mkdir(workspaceClaudeDir, { recursive: true, mode: 0o755 });
const workspaceAxSkillsDir = path.join(input.workspaceRoot, '.ax', 'skills');
await fs.mkdir(workspaceAxSkillsDir, { recursive: true, mode: 0o755 });
const symlinkPath = path.join(workspaceClaudeDir, 'skills');
// Idempotency: if the symlink (or stale file) already exists, drop it
// first. Don't follow — we want a clean rebuild.
await fs.rm(symlinkPath, { force: true });
await fs.symlink('../.ax/skills', symlinkPath);
```

Then update the sessionEnv literal to include HOME + CLAUDE_CONFIG_DIR:

```typescript
const sessionEnv: Record<string, string> = {
  AX_RUNNER_ENDPOINT: runnerEndpoint,
  AX_SESSION_ID: created.sessionId,
  AX_AUTH_TOKEN: created.token,
  AX_WORKSPACE_ROOT: input.workspaceRoot,
  HOME: homeDir,
  CLAUDE_CONFIG_DIR: claudeConfigDir,
};
```

Important caveat about HOME override: read the existing comment around lines 324-332 about allowlist merge order. HOME is in the allowlist FROM the parent — sessionEnv merges LAST so the override wins. Verify this is still the case after your change.

